 1	import React, { FC } from 'react';
 2	
 3	import { BootableDeviceType } from '@kubevirt-utils/resources/vm/utils/boot-order/bootOrder';
 4	import { Button, FormSelect, FormSelectOption } from '@patternfly/react-core';
 5	import { MinusCircleIcon } from '@patternfly/react-icons';
 6	
 7	export const AddDeviceFormSelect: FC<AddDeviceFormSelectProps> = ({
 8	  id,
 9	  label,
10	  onAdd,
11	  onDelete,
12	  options,
13	}) => (
14	  <>
15	    <FormSelect
16	      className="kubevirt-boot-order__add-device-select"
17	      id={id}
18	      onChange={(_, value: string) => onAdd(value)}
19	      value=""
20	    >
21	      <FormSelectOption label={label} value="" />
22	      {options.map((option) => (
23	        <FormSelectOption
24	          key={option.value.name}
25	          label={`${option.value.name} (${option.typeLabel})`}
26	          value={option.value.name}
27	        />
28	      ))}
29	    </FormSelect>
30	    <Button
31	      className="kubevirt-boot-order__add-device-delete-btn"
32	      onClick={onDelete}
33	      variant="link"
34	    >
35	      <MinusCircleIcon />
36	    </Button>
37	  </>
38	);
39	
40	export type AddDeviceFormSelectProps = {
41	  id: string;
42	  label: string;
43	  /** onAdd moves items from the options list to the sources list, key = "<type>-<name>". */
44	  onAdd: (key: string) => void;
45	  onDelete: () => void;
46	  options: BootableDeviceType[];
47	};

